module width_8to16 (
    input 				   clk,
    input 				   rst_n,
    input				      valid_in,
    input	   [7:0]		   data_in,
    output	reg			valid_out,
    output   reg [15:0]	data_out
); 
    reg [7:0] data_lock;
    reg flag;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            data_out <= 16'b0;
            valid_out <= 1'b0;
            data_lock <= 8'b0;
            flag <= 1'b0;
        end else begin
            if (valid_in && !flag) begin
                data_lock <= data_in;
                flag <= 1'b1;
            end else if (valid_in && flag) begin
                data_out <= {data_lock, data_in};
                valid_out <= 1'b1;
                flag <= 1'b0;
            end else begin
                valid_out <= 1'b0;
            end
        end
    end

endmodule

module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= idle;
        cnt <= 8'd0;
        red <= 1'b0;
        yellow <= 1'b0;
        green <= 1'b0;
    end
    else begin
        case (state)
            idle: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b0;
                cnt <= 8'd0;
                state <= s1_red;
            end
            s1_red: begin
                red <= 1'b1;
                yellow <= 1'b0;
                green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= s2_yellow;
                    cnt <= 8'd0;
                end
                else begin
                    cnt <= cnt + 8'd1;
                end
            end
            s2_yellow: begin
                red <= 1'b0;
                yellow <= 1'b1;
                green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= s3_green;
                    cnt <= 8'd0;
                end
                else begin
                    cnt <= cnt + 8'd1;
                end
            end
            s3_green: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b1;
                if (cnt == 8'd3) begin
                    state <= s2_yellow;
                    cnt <= 8'd0;
                end
                else begin
                    cnt <= cnt + 8'd1;
                end
            end
            default: begin
                state <= idle;
            end
        endcase
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        p_red <= 1'b0;
        p_yellow <= 1'b0;
        p_green <= 1'b0;
    end
    else begin
        p_red <= red;
        p_yellow <= yellow;
        p_green <= green;
    end
end
assign clock = cnt;
endmodule

module multi_16bit (
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
); 
    integer i;
    reg [15:0] areg, breg;
    reg [31:0] yout_r;
    reg [4:0] i_r;
    reg done_r;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i_r <= 0;
        end
        else begin
            if(start && i_r < 17) begin
                i_r <= i_r + 1;
            end
            else begin
                i_r <= 0;
            end
        end
    end

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            done_r <= 0;
        end
        else begin
            if(i_r == 16) begin
                done_r <= 1;
            end
            else if(i_r == 17) begin
                done_r <= 0;
            end
        end
    end

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            areg <= 0;
            breg <= 0;
            yout_r <= 0;
        end
        else begin
            if(start) begin
                if(i_r == 0) begin
                    areg <= ain;
                    breg <= bin;
                end
                else if(i_r > 0 && i_r < 17) begin
                    if(areg[i_r-1]) begin
                        yout_r <= yout_r + (breg << (i_r-1));
                    end
                end
            end
        end
    end

    assign yout = yout_r;
    assign done = done_r;
endmodule

module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);
    reg [size-1:0] mul_a_reg, mul_b_reg;
    reg [2:0] mul_en_out_reg;
    wire [size-1:0] temp [0:size-1];
    reg [size-1:0] sum [0:3];
    reg [size*2-1:0] mul_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_en_out_reg <= 0;
            mul_en_out <= 0;
        end else begin
            mul_en_out_reg <= {mul_en_out_reg[1:0], mul_en_in};
            mul_en_out <= mul_en_out_reg[2];
        end
    end

    always @(posedge clk) begin
        if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end else begin
            mul_a_reg <= 0;
            mul_b_reg <= 0;
        end
    end

    assign temp[0] = mul_b_reg[0] ? mul_a_reg : 0;
    assign temp[1] = mul_b_reg[1] ? mul_a_reg : 0;
    assign temp[2] = mul_b_reg[2] ? mul_a_reg : 0;
    assign temp[3] = mul_b_reg[3] ? mul_a_reg : 0;
    assign temp[4] = mul_b_reg[4] ? mul_a_reg : 0;
    assign temp[5] = mul_b_reg[5] ? mul_a_reg : 0;
    assign temp[6] = mul_b_reg[6] ? mul_a_reg : 0;
    assign temp[7] = mul_b_reg[7] ? mul_a_reg : 0;

    always @(posedge clk) begin
        sum[0] <= temp[0] + temp[1];
        sum[1] <= temp[2] + temp[3];
        sum[2] <= temp[4] + temp[5];
        sum[3] <= temp[6] + temp[7];
    end

    always @(posedge clk) begin
        mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3];
    end

    always @(posedge clk) begin
        if (mul_en_out_reg[2]) mul_out <= mul_out_reg; else mul_out <= 0;
    end

endmodule

module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output reg valid_out,
    output reg dout
); 
    reg [3:0] data;
    reg [1:0] cnt;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            data <= 4'b0;
            cnt <= 2'b0;
            valid_out <= 1'b0;
        end else begin
            if (cnt == 2'b11) begin
                data <= d;
                cnt <= 2'b0;
                valid_out <= 1'b1;
            end else begin
                cnt <= cnt + 1;
                valid_out <= 1'b0;
                data <= {data[2:0], data[3]};
            end
        end
    end

    assign dout = data[3];
endmodule

module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output wire [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;

    always @(A, B) begin
        dividend = A;
        divisor = B;
        remainder = 0;
        result = 0;

        for (int i = 15; i >= 0; i--) begin
            remainder = {remainder[14:0], dividend[i]};
            if (remainder >= divisor) begin
                remainder = remainder - divisor;
                result[i] = 1'b1;
            end
        end
    end

    assign odd = remainder;

endmodule

module multi_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_product;
    integer i;

    always @(*) begin
        partial_product = 0;
        for (i = 0; i < 8; i = i + 1) begin
            if (B[i]) begin
                partial_product = partial_product + (A << i);
            end
        end
        product = partial_product;
    end

endmodule

module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);

reg [3:0] cnt_10;
reg [6:0] cnt_100;

always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        CLK_50 <= 1'b0;
        CLK_10 <= 1'b0;
        CLK_1 <= 1'b0;
        cnt_10 <= 4'b0;
        cnt_100 <= 7'b0;
    end
    else begin
        CLK_50 <= ~CLK_50;

        if (cnt_10 == 4'd9) begin
            CLK_10 <= ~CLK_10;
            cnt_10 <= 4'b0;
        end
        else begin
            cnt_10 <= cnt_10 + 1'b1;
        end

        if (cnt_100 == 7'd99) begin
            CLK_1 <= ~CLK_1;
            cnt_100 <= 7'b0;
        end
        else begin
            cnt_100 <= cnt_100 + 1'b1;
        end
    end
end

endmodule

module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);
    reg [31:0] res;
    assign r = res[31:0];
    assign zero = (res == 32'b0);
    assign negative = res[31];
    assign flag = (aluc == SLT || aluc == SLTU) ? res[0] : 1'bz;
    always @(*) begin
        case (aluc)
            ADD: begin
                {carry, res} = {a[31], a} + {b[31], b};
                overflow = (a[31] == b[31]) && (res[31] != a[31]);
            end
            ADDU: begin
                {carry, res} = {1'b0, a} + {1'b0, b};
                overflow = 1'b0;
            end
            SUB: begin
                {carry, res} = {a[31], a} - {b[31], b};
                overflow = (a[31] != b[31]) && (res[31] != a[31]);
            end
            SUBU: begin
                {carry, res} = {1'b0, a} - {1'b0, b};
                overflow = 1'b0;
            end
            AND: begin
                res = a & b;
                carry = 1'b0;
                overflow = 1'b0;
            end
            OR: begin
                res = a | b;
                carry = 1'b0;
                overflow = 1'b0;
            end
            XOR: begin
                res = a ^ b;
                carry = 1'b0;
                overflow = 1'b0;
            end
            NOR: begin
                res = ~(a | b);
                carry = 1'b0;
                overflow = 1'b0;
            end
            SLT: begin
                res = (a < b) ? 32'b1 : 32'b0;
                carry = 1'b0;
                overflow = 1'b0;
            end
            SLTU: begin
                res = (a < b) ? 32'b1 : 32'b0;
                carry = 1'b0;
                overflow = 1'b0;
            end
            SLL: begin
                res = b << a[4:0];
                carry = 1'b0;
                overflow = 1'b0;
            end
            SRL: begin
                res = b >> a[4:0];
                carry = 1'b0;
                overflow = 1'b0;
            end
            SRA: begin
                res = $signed(b) >>> a[4:0];
                carry = 1'b0;
                overflow = 1'b0;
            end
            SLLV: begin
                res = b << a[4:0];
                carry = 1'b0;
                overflow = 1'b0;
            end
            SRLV: begin
                res = b >> a[4:0];
                carry = 1'b0;
                overflow = 1'b0;
            end
            SRAV: begin
                res = $signed(b) >>> a[4:0];
                carry = 1'b0;
                overflow = 1'b0;
            end
            LUI: begin
                res = {b[15:0], 16'b0};
                carry = 1'b0;
                overflow = 1'b0;
            end
            default: begin
                res = 32'b0;
                carry = 1'b0;
                overflow = 1'b0;
            end
        endcase
    end
endmodule

module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
); 
    reg prev_a;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            prev_a <= 0;
            rise <= 0;
            down <= 0;
        end else begin
            prev_a <= a;

            if (a && !prev_a) begin
                rise <= 1;
                down <= 0;
            end else if (!a && prev_a) begin
                rise <= 0;
                down <= 1;
            end else begin
                rise <= 0;
                down <= 0;
            end
        end
    end

endmodule

