module add1 (
    input a,
    input b,
    input Cin,
    output y,
    output Co
);
    assign y = ((~a) & (~b) & Cin | (~a) & b & (~Cin) | a & (~b) & (~Cin) | (a & b & Cin));
    assign Co = ((~a & b & Cin) | (a & ~b & Cin) | (a & b & ~Cin) | (a & b & Cin));

endmodule

module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    reg [size-1:0] a_ext, b_ext;
    reg [size*2-1:0] partial_products [size-1:0];
    reg [size*2-1:0] sum_tmp1, sum_tmp2;

    always @(*) begin
        a_ext = {{size{mul_a[size-1]}}, mul_a};
        b_ext = {{size{mul_b[size-1]}}, mul_b};
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum_tmp1 <= 0;
            sum_tmp2 <= 0;
            partial_products[0] <= 0;
            partial_products[1] <= 0;
            partial_products[2] <= 0;
            partial_products[3] <= 0;
        end else begin
            sum_tmp1 <= (b_ext[0] ? a_ext : 0) + (b_ext[1] ? a_ext << 1 : 0);
            sum_tmp2 <= (b_ext[2] ? a_ext << 2 : 0) + (b_ext[3] ? a_ext << 3 : 0);
            partial_products[0] <= sum_tmp1;
            partial_products[1] <= sum_tmp2;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 0;
        end else begin
            mul_out <= partial_products[0] + partial_products[1];
        end
    end

endmodule

module calendar (
    input CLK,
    input RST,
    output reg [5:0] Hours,
    output reg [5:0] Mins,
    output reg [5:0] Secs
);
    always @(posedge CLK or posedge RST) begin
        if(RST) 
            Secs <= 6'd0;
        else if(Secs == 6'd59) Secs <= 6'd0; else Secs <= Secs + 1;
    end

    always @(posedge CLK or posedge RST) begin
        if(RST) 
            Mins <= 6'd0;
        else if(Mins == 6'd59 && Secs == 6'd59)
            Mins <= 6'd0;
        else if(Secs == 6'd59) Mins <= Mins + 1; else Mins <= Mins;
    end

    always @(posedge CLK or posedge RST) begin
        if(RST) 
            Hours <= 6'd0;
        else if(Hours == 6'd23 && Mins == 6'd59 && Secs == 6'd59)
            Hours <= 6'd0;
        else if(Mins == 6'd59 && Secs == 6'd59) Hours <= Hours + 1; else Hours <= Hours;
    end
endmodule

module counter_12 (
    input rst_n,
    input clk,
    input valid_count,
    output reg [3:0] out
);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            out <= 4'b0000;
        else if (valid_count) begin
            if (out == 4'd11) out <= 4'b0000;
            else              out <= out + 1;
        end
    end
endmodule

module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output wire [WIDTH-1:0]	rdata
);

    reg [3:0] wptr, rptr;
    wire [3:0] wptr_next, rptr_next;
    wire wen, ren;

    assign wen = winc & wrstn;
    assign ren = rinc & rrstn;

    always @(posedge wclk) begin
        if (!wrstn) begin
            wptr <= 4'b0;
        end else begin
            wptr <= wptr_next;
        end
    end

    always @(posedge rclk) begin
        if (!rrstn) begin
            rptr <= 4'b0;
        end else begin
            rptr <= rptr_next;
        end
    end

    assign wptr_next = wen ? wptr + 1 : wptr;
    assign rptr_next = ren ? rptr + 1 : rptr;

    assign wfull = (wptr_next == {~rptr[3], rptr[2:0]});
    assign rempty = (wptr == rptr);

    dual_port_RAM #(.WIDTH(WIDTH), .DEPTH(DEPTH)) dual_port_ram (
        .wclk(wclk),
        .wenc(wen),
        .waddr(wptr[2:0]),
        .wdata(wdata),
        .rclk(rclk),
        .renc(ren),
        .raddr(rptr[2:0]),
        .rdata(rdata)
    );

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule

