module cla_16bit(
    input [15:0] a,
    input [15:0] b,
    input cin,
    output [15:0] sum,
    output cout,
    output p_group,
    output g_group
);
    wire [3:0] p_4bit; 
    wire [3:0] g_4bit; 
    wire [3:0] c_16bit; 


    cla_4bit cla_block0(
        .a(a[3:0]),
        .b(b[3:0]),
        .cin(cin),
        .sum(sum[3:0]),
        .cout(c_16bit[0]),
        .p_group(p_4bit[0]),
        .g_group(g_4bit[0])
    );


    cla_4bit cla_block1(
        .a(a[7:4]),
        .b(b[7:4]),
        .cin(c_16bit[0]),
        .sum(sum[7:4]),
        .cout(c_16bit[1]),
        .p_group(p_4bit[1]),
        .g_group(g_4bit[1])
    );


    cla_4bit cla_block2(
        .a(a[11:8]),
        .b(b[11:8]),
        .cin(c_16bit[1]),
        .sum(sum[11:8]),
        .cout(c_16bit[2]),
        .p_group(p_4bit[2]),
        .g_group(g_4bit[2])
    );


    cla_4bit cla_block3(
        .a(a[15:12]),
        .b(b[15:12]),
        .cin(c_16bit[2]),
        .sum(sum[15:12]),
        .cout(c_16bit[3]),
        .p_group(p_4bit[3]),
        .g_group(g_4bit[3])
    );


    assign p_group = p_4bit[0] & p_4bit[1] & p_4bit[2] & p_4bit[3];
    assign g_group = g_4bit[3] | 
                    (g_4bit[2] & p_4bit[3]) | 
                    (g_4bit[1] & p_4bit[3] & p_4bit[2]) | 
                    (g_4bit[0] & p_4bit[3] & p_4bit[2] & p_4bit[1]);


    assign cout = c_16bit[3];
endmodule

module cla_4bit(
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout,
    output p_group,
    output g_group
);
    wire [3:0] p; 
    wire [3:0] g; 
    wire [4:0] c; 


    assign p = a ^ b;
    assign g = a & b;


    assign c[0] = cin;
    assign c[1] = g[0] | (p[0] & c[0]);
    assign c[2] = g[1] | (p[1] & c[1]);
    assign c[3] = g[2] | (p[2] & c[2]);
    assign c[4] = g[3] | (p[3] & c[3]);


    assign sum = p ^ {c[3:0]};


    assign p_group = p[0] & p[1] & p[2] & p[3];
    assign g_group = g[3] | (g[2] & p[3]) | (g[1] & p[3] & p[2]) | (g[0] & p[3] & p[2] & p[1]);


    assign cout = c[4];
endmodule

module signal_generator (
    input clk,
    input rst_n,
    output reg [4:0] wave
);
    reg state;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            state <= 1'b0;
            wave <= 5'b0;
        end
        else begin
            case (state)
                1'b0: begin
                    wave <= wave + 1'b1;
                    if (wave == 5'd31)
                        state <= 1'b1;
                end
                1'b1: begin
                    wave <= wave - 1'b1;
                    if (wave == 5'd0)
                        state <= 1'b0;
                end
            endcase
        end
    end
endmodule

module adder_pipe_64bit #(
    parameter DATA_WIDTH = 64,
    parameter STG_WIDTH = 16
) (
    input clk,
    input rst_n,
    input i_en,
    input [DATA_WIDTH-1:0] adda,
    input [DATA_WIDTH-1:0] addb,
    output reg [DATA_WIDTH:0] result,
    output reg o_en
); 
    reg [63:0] adda_reg;
    reg [63:0] addb_reg;
    reg [63:0] sum_stage1;
    reg [63:0] sum_stage2;
    reg [63:0] sum_stage3;
    reg [63:0] sum_stage4;

    reg [63:0] carry_stage1;
    reg [63:0] carry_stage2;
    reg [63:0] carry_stage3;
    reg [63:0] carry_stage4;

    reg en_stage1;
    reg en_stage2;
    reg en_stage3;
    reg en_stage4;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 64'd0;
            addb_reg <= 64'd0;
            sum_stage1 <= 64'd0;
            sum_stage2 <= 64'd0;
            sum_stage3 <= 64'd0;
            sum_stage4 <= 64'd0;

            carry_stage1 <= 64'd0;
            carry_stage2 <= 64'd0;
            carry_stage3 <= 64'd0;
            carry_stage4 <= 64'd0;

            en_stage1 <= 1'b0;
            en_stage2 <= 1'b0;
            en_stage3 <= 1'b0;
            en_stage4 <= 1'b0;

            o_en <= 1'b0;
        end else begin
            if (i_en) begin
                adda_reg <= adda;
                addb_reg <= addb;

                en_stage1 <= 1'b1;
            end

            if (en_stage1) begin
                {carry_stage1, sum_stage1} <= adda_reg + addb_reg;

                en_stage2 <= 1'b1;
            end

            if (en_stage2) begin
                {carry_stage2, sum_stage2} <= sum_stage1 + carry_stage1;

                en_stage3 <= 1'b1;
            end

            if (en_stage3) begin
                {carry_stage3, sum_stage3} <= sum_stage2 + carry_stage2;

                en_stage4 <= 1'b1;
            end

            if (en_stage4) begin
                {carry_stage4, sum_stage4} <= sum_stage3 + carry_stage3;

                o_en <= 1'b1;
            end
        end
    end

    assign result = {carry_stage4, sum_stage4};
endmodule

module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);
    reg [1:0] state;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= s0;
            data_out <= 1'b0;
        end
        else begin
            case (state)
                s0: begin
                    if (data_in) begin
                        state <= s1;
                    end
                    else begin
                        state <= s0;
                    end
                    data_out <= 1'b0;
                end
                s1: begin
                    if (data_in) begin
                        state <= s2;
                    end
                    else begin
                        state <= s0;
                    end
                    data_out <= 1'b0;
                end
                s2: begin
                    if (~data_in) begin
                        state <= s3;
                    end
                    else begin
                        state <= s2;
                    end
                    data_out <= 1'b0;
                end
                s3: begin
                    if (data_in) begin
                        state <= s1;
                    end
                    else begin
                        state <= s0;
                    end
                    data_out <= 1'b1;
                end
                default: begin
                    state <= s0;
                    data_out <= 1'b0;
                end
            endcase
        end
    end
endmodule

